#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <unistd.h>
#include <stdint.h>
#include <sys/time.h>
#include <cuda_runtime.h>

void run(int argc, char** argv);

__inline__ uint64_t rdtsc()
{
    uint32_t lo, hi;
    __asm__ __volatile__("rdtsc" : "=a"(lo), "=d"(hi));
    return ((uint64_t)hi << 32) | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc() - start_cycles)

struct timeval starttime;
struct timeval endtime;

#define startTime()            \
    {                          \
        gettimeofday(&starttime, 0); \
    }
#define stopTime(valusecs)                                                         \
    {                                                                              \
        gettimeofday(&endtime, 0);                                                 \
        valusecs = (endtime.tv_sec - starttime.tv_sec) * 1000000 + endtime.tv_usec - starttime.tv_usec; \
    }

#define pin_stats_reset() startCycle()
#define pin_stats_pause(cycles) stopCycle(cycles)
#define pin_stats_dump(cycles) printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void init(int argc, char** argv)
{
    if (3 == argc) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    } else {
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; rows > n; n++)
        wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++) {
        for (int j = 0; cols > j; j++) {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; cols > j; j++)
        result[j] = wall[0][j];

#ifdef BENCH_PRINT
    for (int i = 0; rows > i; i++) {
        for (int j = 0; cols > j; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char* s)
{
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? min : ((x > (max)) ? max : x)
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__global__ void path_kernel(const int* src, int* dst, const int* wall_row, int ncols)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < ncols) {
        int minv = src[n];
        if (0 < n)
            minv = MIN(minv, src[n - 1]);
        if (ncols - 1 > n)
            minv = MIN(minv, src[n + 1]);
        dst[n] = wall_row[n] + minv;
    }
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;
    int* src;
    int* dst;
    int* temp;

    dst = result;
    src = new int[cols];

    int* d_data = NULL;
    int* d_src = NULL;
    int* d_dst = NULL;
    int* d_temp = NULL;

    cudaMalloc((void**)&d_data, sizeof(int) * rows * cols);
    cudaMalloc((void**)&d_src, sizeof(int) * cols);
    cudaMalloc((void**)&d_dst, sizeof(int) * cols);

    cudaMemcpy(d_data, data, sizeof(int) * rows * cols, cudaMemcpyHostToDevice);
    cudaMemcpy(d_dst, result, sizeof(int) * cols, cudaMemcpyHostToDevice);

    int threads = 256;
    int blocks = (cols + threads - 1) / threads;

    pin_stats_reset();
    for (int t = 0; rows - 1 > t; t++) {
        temp = src;
        src = dst;
        dst = temp;

        d_temp = d_src;
        d_src = d_dst;
        d_dst = d_temp;

        const int* d_wall_row = d_data + (t + 1) * cols;
        path_kernel<<<blocks, threads>>>(d_src, d_dst, d_wall_row, cols);
    }
    cudaDeviceSynchronize();
    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    cudaMemcpy(dst, d_dst, sizeof(int) * cols, cudaMemcpyDeviceToHost);

#ifdef BENCH_PRINT
    for (int i = 0; cols > i; i++)
        printf("%d ", data[i]);
    printf("\n");

    for (int i = 0; cols > i; i++)
        printf("%d ", dst[i]);
    printf("\n");
#endif

    cudaFree(d_data);
    cudaFree(d_src);
    cudaFree(d_dst);

    delete[] data;
    delete[] wall;
    delete[] dst;
    delete[] src;
}
